#include <stdio.h>
#include <stddef.h>

typedef struct {
    char a;
    int b;
    char c;
    double d;
    char e;
} Padded;

typedef struct {
    double d;
    int b;
    char a;
    char c;
    char e;
} Packed;

int main(void) {
    printf("=== Padded ===\n");
    printf("sizeof = %zu\n", sizeof(Padded));
    printf("offsetof(a) = %zu\n", offsetof(Padded, a));
    printf("offsetof(b) = %zu\n", offsetof(Padded, b));
    printf("offsetof(c) = %zu\n", offsetof(Padded, c));
    printf("offsetof(d) = %zu\n", offsetof(Padded, d));
    printf("offsetof(e) = %zu\n", offsetof(Padded, e));

    printf("=== Packed ===\n");
    printf("sizeof = %zu\n", sizeof(Packed));
    printf("offsetof(d) = %zu\n", offsetof(Packed, d));
    printf("offsetof(b) = %zu\n", offsetof(Packed, b));
    printf("offsetof(a) = %zu\n", offsetof(Packed, a));

    printf("Economie : %zu octets\n", sizeof(Padded) - sizeof(Packed));
    return 0;
}

